import{_ as r,o as t,c as s,j as e,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"六库仙贼","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/能量类/六库仙贼.md","filePath":"4.资源分区/6.技艺及称号/能量类/六库仙贼.md"}'),p={name:"4.资源分区/6.技艺及称号/能量类/六库仙贼.md"};function d(l,a,_,i,c,h){return t(),s("div",null,[...a[0]||(a[0]=[e("h1",{id:"六库仙贼",tabindex:"-1"},[n("六库仙贼 "),e("a",{class:"header-anchor",href:"#六库仙贼","aria-label":'Permalink to "六库仙贼"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),o('<h1 id="六库仙贼-1" tabindex="-1">六库仙贼 <a class="header-anchor" href="#六库仙贼-1" aria-label="Permalink to &quot;六库仙贼&quot;">​</a></h1><p>六库仙贼<br> 价格：A+4000<br> 六库仙贼是为“圣人盗”，取其圣人不死，大盗不止之意 。所谓六库，实为六脏，是人精气所在，为人活于世的根本。仙贼是以贼问仙，靠盗窃天地生机，充盈六库，以期可以延年益寿，永享安康。</p><p>所有修道者最终所求无非性命双全。百姓’之性, ‘性命’之性，在先秦古文皆作“生 ”而修炼者最是贵“生”，所道者所求，应不从女，不从心，追求身心全面修炼，而六库仙贼却不同，它是完完全全的修命之法，修成者往往命强而性弱，有生而无贵，最终落得了个“可是活腻了”的精神病态弱点，但这种弱点却很难说是六库仙贼之过，无非是修炼者德不配位而已。<br> 对于六库仙贼修炼者来说，修成之刻才是修炼的开始，世间百苦，亦为大道之磨砺！</p><p>前提：拥有炁、内力、真气中任意一种。</p><p>【食气者神明】<br> “六库仙贼”是以大肠、小肠、胃、三焦、胆、膀胱这六个器官为基础，然后打造出的一套完美的吸收消化系统，通过窃取天地生机，吸收天地之间的养分化为己用，以此六库充盈，吸收的养分无漏无垢，即使是不可吸收的，也会利用四肢百骸藉由每一次呼吸排除，没有即存在体内异化成毒素的机会，对身体脏器再无负担。<br> 在六库仙贼入门后，人物从此变得无味无垢，无惧寒暑，与自然天地同为一体，无需食水或睡眠便可存活，身体停止衰老，视为具有了A级【毒素】免疫以及免疫C级【环境】来源的效果。</p><p>【而不死】<br> 于此同时，在学习六库仙贼后，人物便可将天地升级转化为自己的能量，这种夺天地造化为己用的做法才是是“六库仙贼”真正的工用。通过“六库仙贼”的能力运转，天地之间的任何东西在体内消化系统中完美消化，转化为自身的生机，这种生机可以随意使用，而且更是取之不尽用之不竭。<br> 人物获得一种特殊的攻击和恢复身体的方式，每轮一次，标准动作消耗14点能量使用，放出能量覆盖周身，对触及范围内所有生物或某一生物进行一次你具有的攻击方式的攻击检定，这视为一个攻击技。造成腐蚀伤害，同时激活等同于造成伤害数/3的吸血，这些吸血是六库仙贼提供的，在使用后立即消失。获得的吸血点数上限自身耐力属性值一半与伤害出目/3取低。<br> ps：攻击并不限于人类，或者说，其原本用法就并非人类敌人，人物可以通过对周围的草木蚊虫等任何有生命造成伤害，也可以抽取其生机，获得医疗点以治疗自身。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=r(p,[["render",d]]);export{f as __pageData,m as default};
